t-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.pts-log-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:20px}\n.pts-log-item{display:flex;gap:16px;align-items:flex-start;background:#fff;border-radius:12px;padding:20px}\n.pts-log-icon{width:40px;height:40px;border-radius:8px;background:rgba(3,105,161,0.1);display:flex;align-items:center;justify-content:center;flex-shrink:0}\n.pts-log-icon svg{stroke:#0369a1}\n.pts-log-item-label{font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;color:#000864;margin-bottom:2px}\n.pts-log-item-value{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#333;line-height:1.5}\n\n.et_pb_section .pts-log-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .pts-log-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .pts-log-item-label,.et_pb_section .pts-log-item-value{-webkit-font-smoothing:auto !important}\n\n@media(max-width:768px){\n  .pts-log-grid{grid-template-columns:1fr}\n  .pts-log-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.pts-log-section *{transition:none !important}}\n/* === REGISTRATION CTA === */\n.pts-reg-section{background:linear-gradient(165deg,#0f1419 0%,#1a2632 40%,#000864 100%);padding:80px 24px;text-align:center;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.pts-reg-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.pts-reg-section