'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.pts-rel-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.pts-rel-card{background:#fff;border-radius:16px;overflow:hidden;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.pts-rel-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.pts-rel-card-border{height:4px}\n.pts-rel-card-body{padding:28px}\n.pts-rel-badge{display:inline-block;font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;padding:4px 12px;border-radius:50px;margin-bottom:12px}\n.pts-rel-card h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;line-height:1.4;margin:0 0 16px;padding:0}\n.pts-rel-meta{display:flex;flex-direction:column;gap:8px;margin-bottom:16px}\n.pts-rel-meta-item{display:flex;align-items:center;gap:6px;font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80}\n.pts-rel-meta-item svg{flex-shrink:0;stroke:#94a3b8}\n.pts-rel-link{display:inline-flex;align-items:center;gap:4px;font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;text-decoration:none;transition:opacity 0.3s ease}\n.pts-rel-link:hover{opacity:0.8}\n\n.et_pb_section .pts-rel-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .pts-rel-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .pts-rel-card h3{-webkit-font-smoothing:auto !important;margin:0 0 16px !important;padding:0 !important}\n\n@media(max-width:768px){\n  .pts-rel-grid{grid-template-columns:1fr}\n  .pts-rel-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.pts-rel-card{transition:none !important}}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-hero-section">\n  <div class="pts-hero-superd" aria-hidden="true"></div>\n  <a href="/news/" class="pts-hero-back">\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>\n    Back to News &amp; Events\n  </a>\n  <span class="pts-hero-badge">Seminar</span>\n  <h1>Production Transparency: From Paper Reports to Real-Time Dashboards</h1>\n  <p class="pts-hero-subtitle">Discover how factories replace paper-based reporting with live production dashboards that surface issues before they become costly delays.</p>\n\n  <div class="pts-hero-facts">\n    \n      <div class="pts-hero-fact">\n        <div class="pts-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n        </div>\n        <div class="pts-hero-fact-value">April 10, 2026</div>\n        <div class="pts-hero-fact-label">Thursday</div>\n      </div>\n\n      <div class="pts-hero-fact">\n        <div class="pts-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n        </div>\n        <div class="pts-hero-fact-value">13:00 – 17:00</div>\n        <div class="pts-hero-fact-label">Half Day</div>\n      </div>\n\n      <div class="pts-hero-fact">\n        <div class="pts-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n        </div>\n        <div class="pts-hero-fact-value">Bangkok</div>\n        <div class="pts-hero-fact-label">Thailand</div>\n      </div>\n\n      <div class="pts-hero-fact">\n        <div class="pts-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4-4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87"/><path d="M16 3.13a4 4 0 010 7.75"/></svg>\n        </div>\n        <div class="pts-hero-fact-value">50 Seats</div>\n        <div class="pts-hero-fact-label">Limited</div>\n      </div>\n  </div>\n\n  <a href="#register" class="pts-hero-cta">\n    Reserve Your Seat\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n  </a>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-prob-section">\n  <div class="pts-prob-inner">\n    <span class="pts-prob-label">The Challenge</span>\n    <h2 class="pts-prob-title">Your Shop Floor Data Is Always a Day Behind</h2>\n  </div>\n  <div class="pts-prob-body">\n    \n    <p>Most Thai factories still rely on paper reports filled out at shift-end. Operators jot down production counts, note quality issues in handwriting, and pass clipboards to supervisors who key the numbers into spreadsheets the following morning. By the time management sees the data, it\'s already yesterday\'s news.</p>\n\n    <p>The real cost isn\'t just the delay — it\'s the decisions made without current information. Managers allocate resources based on numbers that no longer reflect reality. Quality issues that could have been caught in minutes go unnoticed for hours, turning a small defect into an entire batch of scrap. A machine running below capacity doesn\'t get attention until tomorrow\'s report lands on someone\'s desk.</p>\n\n    <p>The difference between catching a problem in real-time and discovering it a day later can be <strong>10x in cost</strong>. MES (Manufacturing Execution System) dashboards change this equation entirely — giving you live production visibility so you can act on what\'s happening now, not what happened yesterday.</p>\n    \n    <div class="pts-prob-data-card">\n      <div class="pts-prob-data-content">\n        <div class="pts-prob-data-number">Paper Reports</div>\n        <div class="pts-prob-data-arrow">&darr;</div>\n        <div class="pts-prob-data-number pts-prob-data-number--success">Real-Time Dashboards</div>\n        <div class="pts-prob-data-label">Catch issues in minutes, not days</div>\n      </div>\n    </div>\n    \n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-out-section">\n  <div class="pts-out-inner">\n    <span class="pts-out-label">Seminar Outcomes</span>\n    <h2 class="pts-out-title">What You\'ll Walk Away With</h2>\n    <div class="pts-out-grid">\n      \n    <div class="pts-out-card">\n      <div class="pts-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><line x1="12" y1="1" x2="12" y2="23"/><path d="M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/></svg>\n      </div>\n      <h3>Understand the cost of delayed production visibility</h3>\n      <p>Quantify what late data actually costs your factory — in scrap, rework, missed deliveries, and overtime.</p>\n    </div>\n\n    <div class="pts-out-card">\n      <div class="pts-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><rect x="2" y="3" width="20" height="14" rx="2" ry="2"/><line x1="8" y1="21" x2="16" y2="21"/><line x1="12" y1="17" x2="12" y2="21"/></svg>\n      </div>\n      <h3>See a live MES dashboard in action with real factory data</h3>\n      <p>Not slides or mockups — a working MES dashboard populated with real production data from a Thai factory.</p>\n    </div>\n\n    <div class="pts-out-card">\n      <div class="pts-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></svg>\n      </div>\n      <h3>Identify which production metrics matter most for your industry</h3>\n      <p>OEE, yield rate, cycle time, first-pass quality — learn which KPIs to track first based on your manufacturing type.</p>\n    </div>\n\n    <div class="pts-out-card">\n      <div class="pts-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><rect x="4" y="2" width="16" height="20" rx="2"/><line x1="8" y1="6" x2="16" y2="6"/><line x1="8" y1="10" x2="16" y2="10"/><line x1="8" y1="14" x2="12" y2="14"/></svg>\n      </div>\n      <h3>Build a business case for real-time shop floor digitization</h3>\n      <p>Leave with a framework to present the ROI of MES to your management team — grounded in real numbers, not vendor promises.</p>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-agd-section">\n  <div class="pts-agd-inner">\n    <span class="pts-agd-label">Half-Day Agenda</span>\n    <h2 class="pts-agd-title">A Structured Afternoon — Not a Sales Pitch</h2>\n    <p class="pts-agd-subtitle">Every session is designed around what you\'ll take home — not what we want to sell.</p>\n  </div>\n  <div class="pts-agd-timeline">\n    \n    <div class="pts-agd-item">\n      <div class="pts-agd-time">13:00 – 13:15</div>\n      <div class="pts-agd-content">\n        <h3>Registration & Networking</h3>\n        <p>Coffee, introductions, and a quick survey of your current production reporting process.</p>\n      </div>\n    </div>\n\n    <div class="pts-agd-item">\n      <div class="pts-agd-time">13:15 – 14:00</div>\n      <div class="pts-agd-content">\n        <h3>Why Paper Reports Cost You More Than You Think</h3>\n        <p>The hidden costs of delayed production data — in scrap, rework, overtime, and missed delivery windows. Real examples from Thai factories.</p>\n      </div>\n    </div>\n\n    <div class="pts-agd-item">\n      <div class="pts-agd-time">14:00 – 14:45</div>\n      <div class="pts-agd-content">\n        <h3>Live Demo — MES Dashboard Walk-Through</h3>\n        <p>A working MES dashboard with real factory data. See production status, quality alerts, and OEE tracking in real time — not slides.</p>\n      </div>\n    </div>\n\n    <div class="pts-agd-item pts-agd-item--break">\n      <div class="pts-agd-time">14:45 – 15:00</div>\n      <div class="pts-agd-content">\n        <h3>Coffee Break</h3>\n        \n      </div>\n    </div>\n\n    <div class="pts-agd-item">\n      <div class="pts-agd-time">15:00 – 15:45</div>\n      <div class="pts-agd-content">\n        <h3>Choosing the Right KPIs for Your Factory</h3>\n        <p>Not every metric matters equally. Learn how to select the production KPIs that drive real improvements for your specific manufacturing type.</p>\n      </div>\n    </div>\n\n    <div class="pts-agd-item">\n      <div class="pts-agd-time">15:45 – 16:30</div>\n      <div class="pts-agd-content">\n        <h3>Panel: Real Factory Experiences with MES</h3>\n        <p>Hear directly from factory operators who made the transition from paper to digital. What worked, what surprised them, and what they\'d do differently.</p>\n      </div>\n    </div>\n\n    <div class="pts-agd-item">\n      <div class="pts-agd-time">16:30 – 17:00</div>\n      <div class="pts-agd-content">\n        <h3>Q&A + Next Steps</h3>\n        <p>Open discussion, individual questions about your factory\'s situation, and guidance on where to start.</p>\n      </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-per-section">\n  <div class="pts-per-inner">\n    <span class="pts-per-label">Who This Is For</span>\n    <h2 class="pts-per-title">Is This Seminar Right for You?</h2>\n    <div class="pts-per-grid">\n      \n    <div class="pts-per-card">\n      <div class="pts-per-accent"></div>\n      <div class="pts-per-body">\n        <div class="pts-per-role">Factory Owner / Plant Manager</div>\n        <span class="pts-per-size">Any Size Manufacturing</span>\n        <p class="pts-per-desc">You\'re responsible for overall factory performance but rely on end-of-day reports to understand what happened on the floor. You want visibility without having to walk over and ask.</p>\n        <p class="pts-per-quote">"I need to know what\'s happening on my floor without walking over and asking."</p>\n      </div>\n    </div>\n\n    <div class="pts-per-card">\n      <div class="pts-per-accent"></div>\n      <div class="pts-per-body">\n        <div class="pts-per-role">Production / Operations Manager</div>\n        <span class="pts-per-size">50-500 Employees</span>\n        <p class="pts-per-desc">You manage daily production schedules and troubleshoot problems as they arise — but you can only fix what you can see. Paper forms give you yesterday\'s picture, not today\'s reality.</p>\n        <p class="pts-per-quote">"I need data I can trust, not numbers from yesterday\'s paper forms."</p>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-prf-section">\n  <div class="pts-prf-inner">\n    <span class="pts-prf-label">Why DigiWin Events</span>\n    <h2 class="pts-prf-title">Learn from the Team That\'s Done This 100+ Times</h2>\n    <div class="pts-prf-stats-bar">\n      \n    <div class="pts-prf-stat">\n      <div class="pts-prf-stat-value">100+</div>\n      <div class="pts-prf-stat-label">Thai Implementations</div>\n    </div>\n\n    <div class="pts-prf-stat">\n      <div class="pts-prf-stat-value">44</div>\n      <div class="pts-prf-stat-label">Years Manufacturing ERP</div>\n    </div>\n\n    <div class="pts-prf-stat">\n      <div class="pts-prf-stat-value">95%</div>\n      <div class="pts-prf-stat-label">Contract Renewal Rate</div>\n    </div>\n\n    <div class="pts-prf-stat">\n      <div class="pts-prf-stat-value">50+</div>\n      <div class="pts-prf-stat-label">Thai Team Members</div>\n    </div>\n    </div>\n    <p class="pts-prf-text">DigiWin has been helping Thai manufacturers digitize their shop floors for 8 years. This seminar distills that experience into a focused afternoon — the same production visibility frameworks our implementation team uses with every MES client.</p>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="pts-log-section">\n  <div class="pts-log-inner">\n    <span class="pts-log-label">Practical Details</span>\n    <h2 class="pts-log-title">Everything You Need to Know</h2>\n    <div class="pts-log-grid">\n      \n    <div class="pts-log-item">\n      <div class="pts-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n      </div>\n      <div>\n        <div class="pts-log-item-label">Date</div>\n        <div class="pts-log-item-value">Thursday, April 10, 2026</div>\n      </div>\n    </div>\n\n    <div class="pts-log-item">\n      <div class="pts-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n      </div>\n      <div>\n        <div class="pts-log-item-label">Time</div>\n        <div class="pts-log-item-value">13:00 – 17:00 (registration opens 12:45)</div>\n      </div>\n    </div>\n\n    <div class="pts-log-item">\n      <div class="pts-log-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="20" height="20"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n      </div>\n      <div>\n        <div class="pts-log-item-label">Location</div>\n        