INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100753, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === EVENT HERO === */\n.pts-hero-section{background:linear-gradient(165deg,#0f1419 0%,#1a2632 40%,#000864 100%);padding:140px 24px 80px;text-align:center;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.pts-hero-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.pts-hero-section>*{position:relative;z-index:2}\n.pts-hero-back{display:inline-flex;align-items:center;gap:6px;font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:500;color:rgba(255,255,255,0.85);text-decoration:none;margin-bottom:24px;transition:color 0.3s ease}\n.pts-hero-back:hover{color:rgba(255,255,255,0.9)}\n.pts-hero-badge{display:inline-flex;align-items:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:1.5px;color:#0369a1;background:rgba(3,105,161,0.15);padding:6px 18px;border:1px solid rgba(3,105,161,0.3);border-radius:50px;margin-bottom:20px}\n.pts-hero-section h1{font-family:\'Noto Sans\',sans-serif;font-size:clamp(28px,4.5vw,44px);font-weight:700;color:#fff;line-height:1.2;max-width:800px;margin:0 auto 20px;padding:0}\n.pts-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:rgba(255,255,255,0.85);line-height:1.7;max-width:700px;margin:0 auto 40px;padding:0}\n.pts-hero-facts{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;max-width:700px;margin:0 auto 40px;background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.1);border-radius:16px;padding:24px}\n.pts-hero-fact{text-align:center}\n.pts-hero-fact-icon{margin-bottom:8px}\n.pts-hero-fact-icon svg{stroke:#0369a1}\n.pts-hero-fact-value{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;color:#fff}\n.pts-hero-fact-label{font-family:\'Noto Sans\',sans-serif;font-size:13px;color:rgba(255,255,255,0.85)}\n.pts-hero-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;color:#fff;background:#0369a1;padding:16px 40px;border-radius:12px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 20px rgba(3,105,161,0.4)}\n.pts-hero-cta:hover{background:rgb(53,135,180);transform:translateY(-2px);box-shadow:0 8px 24px rgba(3,105,161,0.3)}\n\n.et_pb_section .pts-hero-section h1{-webkit-font-smoothing:auto !important;line-height:1.2 !important;max-width:800px !important;margin:0 auto 20px !important;padding:0 !important}\n.et_pb_section .pts-hero-subtitle{-webkit-font-smoothing:auto !important}\n.et_pb_section .pts-hero-fact-value{-webkit-font-smoothing:auto !important;line-height:25.6px !important;margin-bottom:4px !important}\n.et_pb_section .pts-hero-fact-label{-webkit-font-smoothing:auto !important;line-height:20.8px !important}\n.et_pb_section .pts-hero-badge{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .pts-hero-cta{-webkit-font-smoothing:auto !important;line-height:25.6px !important}\n.et_pb_section .pts-hero-back{-webkit-font-smoothing:auto !important}\n.pts-hero-superd{position:absolute;top:auto;right:-5%;bottom:-5%;left:auto;width:35%;min-height:40vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;opacity:0.15;pointer-events:none;z-index:0}\n\n@media(max-width:768px){\n  .pts-hero-section{padding:120px 20px 60px}\n  .pts-hero-facts{grid-template-columns:repeat(2,1fr);gap:20px}\n}\n@media(max-width:480px){\n  .pts-hero-facts{grid-template-columns:1fr}\n  .pts-hero-cta{width:100%;justify-content:center}\n}\n@media(prefers-reduced-motion:reduce){.pts-hero-section *{transition:none !important}}\n/* === THE PROBLEM === */\n.pts-prob-section{background:#fff;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.pts-prob-inner{text-align:center;max-width:800px;margin:0 auto 40px}\n.pts-prob-label{font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0369a1;display:block;margin-bottom:16px}\n.pts-prob-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;line-height:1.25;margin:0 0 16px;padding:0}\n.pts-prob-body{max-width:800px;margin:0 auto}\n.pts-prob-body p{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#333;line-height:1.8;margin:0 0 24px;padding:0}\n.pts-prob-body strong{font-weight:600;color:#000864}\n.pts-prob-data-card{background:linear-gradient(135deg,#0f1419,#1a2632);border-radius:16px;padding:40px;margin:32px 0;text-align:center;position:relative;overflow:hidden}\n.pts-prob-data-card::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none}\n.pts-prob-data-content{position:relative;z-index:2}\n.pts-prob-data-number{font-family:\'JetBrains Mono\',monospace;font-size:48px;font-weight:500;color:#00AFF0;line-height:1.2;margin-bottom:8px}\n.pts-prob-data-arrow{font-size:32px;color:rgba(255,255,255,0.85);line-height:1.6;margin:4px 0}\n.pts-prob-data-number--success{color:#0369a1}\n.pts-prob-data-label{font-family:\'Noto Sans\',sans-serif;font-size:16px;color:rgba(255,255,255,0.9);margin-top:12px}\n.pts-prob-case-link{text-align:center;margin-top:32px}\n.pts-prob-case-link a{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;color:#0369a1;text-decoration:none;transition:color 0.3s ease}\n.pts-prob-case-link a:hover{color:rgb(53,135,180)}\n\n.et_pb_section .pts-prob-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .pts-prob-body p{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n.et_pb_section .pts-prob-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .pts-prob-data-number{-webkit-font-smoothing:auto !important;line-height:57.6px !important}\n.et_pb_section .pts-prob-data-label{-webkit-font-smoothing:auto !important}\n.et_pb_section .pts-prob-case-link{-webkit-font-smoothing:auto !important;margin-top:32px !important;padding-bottom:0 !important}\n.et_pb_section .pts-prob-case-link a{-webkit-font-smoothing:auto !important;line-height:27px !important}\n\n@media(max-width:768px){\n  .pts-prob-title{font-size:28px}\n  .pts-prob-body p{font-size:16px}\n  .pts-prob-data-number{font-size:24px}\n}\n@media(prefers-reduced-motion:reduce){.pts-prob-section *{transition:none !important}}\n/* === OUTCOMES === */\n.pts-out-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.pts-out-inner{max-width:1100px;margin:0 auto}\n.pts-out-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0369a1;margin-bottom:16px}\n.pts-out-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.pts-out-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:24px}\n.pts-out-card{background:#fff;border-radius:16px;padding:32px;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.pts-out-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.pts-out-icon{width:48px;height:48px;border-radius:50%;background:rgba(3,105,161,0.1);display:flex;align-items:center;justify-content:center;margin-bottom:16px}\n.pts-out-icon svg{stroke:#0369a1}\n.pts-out-card h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 8px;padding:0}\n.pts-out-card p{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#5b6b80;line-height:1.6;margin:0;padding:0}\n\n.et_pb_section .pts-out-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .pts-out-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .pts-out-card h3{-webkit-font-smoothing:auto !important;margin:0 0 8px !important;padding:0 !important}\n.et_pb_section .pts-out-card p{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n\n@media(max-width:768px){\n  .pts-out-grid{grid-template-columns:1fr}\n  .pts-out-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.pts-out-card{transition:none !important}}\n/* === AGENDA === */\n.pts-agd-section{background:#fff;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.pts-agd-inner{text-align:center;max-width:800px;margin:0 auto 48px}\n.pts-agd-label{display:block;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0369a1;margin-bottom:16px}\n.pts-agd-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;line-height:1.3;margin:0 0 16px;padding:0}\n.pts-agd-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;margin:0;padding:0}\n.pts-agd-timeline{max-width:800px;margin:0 auto;display:flex;flex-direction:column;gap:0;border-left:3px solid rgba(3,105,161,0.3);padding-left:32px}\n.pts-agd-item{display:flex;gap:24px;padding:20px 0;border-bottom:1px solid #f0f0f0;position:relative}\n.pts-agd-item::before{content:\'\';position:absolute;left:-38px;top:24px;width:10px;height:10px;border-radius:50%;background:#0369a1;border:2px solid #fff}\n.pts-agd-item--break{opacity:0.6}\n.pts-agd-item--break::before{background:#cbd5e1}\n.pts-agd-time{font-family:\'JetBrains Mono\',monospace;font-size:13px;font-weight:500;color:#0369a1;min-width:130px;flex-shrink:0;padding-top:2px}\n.pts-agd-item--break .pts-agd-time{color:#94a3b8}\n.pts-agd-content h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 4px;padding:0}\n.pts-agd-content p{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#5b6b80;line-height:1.6;margin:0;padding:0}\n\n.et_pb_section .pts-agd-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .pts-agd-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .pts-agd-subtitle{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n.et_pb_section .pts-agd-content h3{-webkit-font-smoothing:auto !important;margin:0 0 4px !important;padding:0 !important}\n.et_pb_section .pts-agd-content p{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n\n@media(max-width:768px){\n  .pts-agd-title{font-size:28px}\n  .pts-agd-item{flex-direction:column;gap:4px}\n  .pts-agd-time{min-width:auto}\n  .pts-agd-timeline{padding-left:24px}\n  .pts-agd-item::before{left:-30px}\n}\n@media(prefers-reduced-motion:reduce){.pts-agd-section *{transition:none !important}}\n/* === WHO SHOULD ATTEND === */\n.pts-per-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.pts-per-inner{max-width:1100px;margin:0 auto}\n.pts-per-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0369a1;margin-bottom:16px}\n.pts-per-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.pts-per-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:24px}\n.pts-per-card{background:#fff;border-radius:16px;overflow:hidden;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.pts-per-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.pts-per-accent{height:4px;background:#0369a1}\n.pts-per-body{padding:28px}\n.pts-per-role{font-family:\'Noto Sans\',sans-serif;font-size:20px;font-weight:600;color:#000864;line-height:1.6;margin-bottom:8px}\n.pts-per-size{display:inline-block;font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0369a1;background:rgba(3,105,161,0.1);padding:4px 10px;border-radius:4px;margin-bottom:16px}\n.pts-per-desc{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#5b6b80;line-height:1.6;margin:0 0 16px;padding:0}\n.pts-per-quote{font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:400;color:#5b6b80;font-style:italic;line-height:1.6;margin:0;padding:16px 0 0;border-top:1px solid #f1f5f9}\n\n.et_pb_section .pts-per-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .pts-per-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .pts-per-role{-webkit-font-smoothing:auto !important;line-height:32px !important}\n.et_pb_section .pts-per-size{-webkit-font-smoothing:auto !important;line-height:17.6px !important}\n.et_pb_section .pts-per-desc{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n.et_pb_section .pts-per-quote{-webkit-font-smoothing:auto !important;padding-bottom:0 !important;line-height:22.4px !important}\n\n@media(max-width:1024px){\n  .pts-per-grid{grid-template-columns:1fr}\n}\n@media(max-width:768px){\n  .pts-per-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.pts-per-card{transition:none !important}}\n/* === PROOF / SOCIAL SIGNAL === */\n.pts-prf-section{background:#fff;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.pts-prf-inner{max-width:1100px;margin:0 auto;text-align:center}\n.pts-prf-label{display:block;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#0369a1;margin-bottom:16px}\n.pts-prf-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;line-height:1.25;margin:0 0 16px;padding:0}\n.pts-prf-stats-bar{display:grid;grid-template-columns:repeat(4,1fr);gap:0;background:linear-gradient(135deg,#0f1419,#1a2632);border-radius:16px;padding:40px 32px;margin-bottom:40px}\n.pts-prf-stat{text-align:center;padding:0 16px}\n.pts-prf-stat:not(:last-child){border-right:1px solid rgba(255,255,255,0.1)}\n.pts-prf-stat-value{font-family:\'Noto Sans\',sans-serif;font-size:42px;font-weight:700;color:#0369a1;line-height:1;margin-bottom:8p